{
	"name": "rudel-monorepo",
	"private": true,
	"scripts": {
		"build": "turbo run build",
		"dev": "turbo run dev",
		"lint": "biome check .",
		"lint:fix": "biome check --write .",
		"format": "biome format --write .",
		"check-types": "turbo run check-types",
		"test": "turbo run test",
		"test:env": "doppler run --project rudel --config ci -- bun run test",
		"verify": "doppler run --project rudel --config ci -- turbo run lint check-types test build",
		"release:cli": "bun run ./scripts/release-cli.ts",
		"deploy": "turbo run build",
		"dev:local": "bash scripts/dev-local.sh",
		"infra:up": "docker compose up -d",
		"infra:down": "docker compose down"
	},
	"devDependencies": {
		"@biomejs/biome": "^2.4.0",
		"turbo": "^2.8.9",
		"typescript": "5.9.2"
	},
	"engines": {
		"node": ">=18"
	},
	"packageManager": "bun@1.3.5",
	"workspaces": [
		"apps/*",
		"packages/*"
	],
	"overrides": {
		"@chkit/core": "0.1.0-beta.7",
		"@chkit/clickhouse": "0.1.0-beta.7"
	},
	"dependencies": {
		"postgres": "^3.4.8",
		"rudel": "^0.1.4"
	}
}

{
	"name": "@rudel/sql-schema",
	"version": "0.0.0",
	"private": true,
	"type": "module",
	"main": "./src/index.ts",
	"types": "./src/index.ts",
	"exports": {
		".": "./src/index.ts"
	},
	"scripts": {
		"check-types": "tsc --noEmit",
		"drizzle:check": "drizzle-kit check",
		"drizzle:generate": "drizzle-kit generate",
		"migrate": "bun run src/migrate.ts",
		"migrate:ci": "doppler run --project rudel --config ci -- bun run src/migrate.ts",
		"migrate:prd": "doppler run --project rudel --config prd -- bun run src/migrate.ts"
	},
	"dependencies": {
		"drizzle-orm": "0.45.1",
		"postgres": "^3.4.5"
	},
	"devDependencies": {
		"@rudel/typescript-config": "workspace:*",
		"drizzle-kit": "0.31.8",
		"typescript": "5.9.2"
	}
}

